import { useState } from "react";

export default function useViewer() {

    const [ exibirCard, setExibirCard ] = useState(false)

    function toggleExibirCard(e) {

        console.log(e.target.parentElement);

        if(!exibirCard){
            setExibirCard(true)
        }else if(exibirCard){
            setExibirCard(false)
        }
    };

    return {
        exibirCard,
        toggleExibirCard
    };

}
